cd /home/archon/proj/Cech-Cohomology
python3 - <<'PY'
import re
_SCAFFOLD_RE = re.compile(r"scaffold|skeleton|leave\s+bodies\s+as|declarations?\s+for|does\s+not\s+(yet\s+)?exist|stub\s+out|add\s+the\s+import", re.IGNORECASE)
_LEAN_NAME_RE = re.compile(r"([\w./-]+\.lean)")
text=open(".archon/PROGRESS.md").read(); lines=text.splitlines(); sec=[]; inn=False
for ln in lines:
    if ln.strip().startswith("## Current Objectives"): inn=True; continue
    if inn and ln.startswith("## "): break
    if inn: sec.append(ln)
exempt=set()
for ln in sec:
    if _SCAFFOLD_RE.search(ln):
        for m in _LEAN_NAME_RE.findall(ln): exempt.add(m.split("/")[-1].lower())
for t in ["cechbridge.lean","freepresheafcomplex.lean","cechacyclic.lean"]:
    print(f"  {t}: {'EXEMPT ✓' if t in exempt else 'NOT exempt'}")
PY
echo ""
echo "=== confirm CechAcyclic still has its sorry (kept regardless) ==="
grep -n "  sorry" AlgebraicJacobian/Cohomology/CechAcyclic.lean | head
